import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './App.css';
import { useInView } from 'react-intersection-observer';
import { BrowserRouter as Router, Route, Routes, useNavigate } from 'react-router-dom';

// Ensure BASE_URL is defined using the environment variable or fallback to a default
const BASE_URL = process.env.REACT_APP_API_BASE_URL || 'http://127.0.0.1:5000';

function shuffleArray(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

const Video = ({ src, videoID, onVideoClick }) => {
  const videoRef = useRef(null);
  const { ref, inView } = useInView({
    triggerOnce: true,
    rootMargin: '50px 0px',
  });

  const handleMouseEnter = () => {
    if (videoRef.current) videoRef.current.play();
  };

  const handleMouseLeave = () => {
    if (videoRef.current) videoRef.current.pause();
  };

  return (
    <div ref={ref} style={{ width: '100%', height: 'auto' }}>
      {inView && (
        <video
          ref={videoRef}
          src={src}
          loop
          muted
          playsInline
          onClick={() => onVideoClick(videoID)}
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
          style={{ width: '100%', height: 'auto' }}
        />
      )}
    </div>
  );
};

const Modal = ({ videoInfo, onClose }) => {
  const getEmbeddedVideoUrl = (url) => {
    const vimeoId = url.split("vimeo.com/")[1].split('/')[0];
    return `https://player.vimeo.com/video/${vimeoId}`;
  };

  const handleModalContentClick = (e) => {
    e.stopPropagation();
  };

  return (
    <div className="modal" onClick={onClose}>
      <div className="modal-content" onClick={handleModalContentClick}>
        <span className="close" onClick={onClose}>&times;</span>
        <h2>{videoInfo.videoName}</h2>
        <div className="embed-container">
          <iframe
            src={getEmbeddedVideoUrl(videoInfo.URL)}
            frameBorder="0"
            allow="autoplay; fullscreen"
            allowFullScreen
            title={videoInfo.videoName}
          ></iframe>
        </div>
        <p style={{ whiteSpace: 'pre-wrap' }}>{videoInfo.Description || ''}</p>
      </div>
    </div>
  );
};

function VideoGrid({ scenes }) {
  const navigate = useNavigate();

  const handleVideoNameClick = (videoID) => {
    navigate(`/videos/${videoID}`);
  };

  return (
    <div className="video-grid">
      {scenes.map(scene => (
        <Video
          key={scene.sceneURL}
          src={scene.sceneURL}
          videoID={scene.videoID}
          onVideoClick={() => handleVideoNameClick(scene.videoID)}
        />
      ))}
    </div>
  );
}

function App() {
  return (
    <div className="App">
      {/* Your menu here */}
      {/* Your video grid and modal routes here */}
    </div>
  );
}

function AppWrapper() {
  const [scenes, setScenes] = useState([]);
  const [uniqueVideoIDs, setUniqueVideoIDs] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    // Fetch scenes
    axios.get(`${BASE_URL}/scenes`)
      .then(response => {
        setScenes(shuffleArray(response.data));
      })
      .catch(error => {
        console.error('Error fetching scenes: ', error);
      });

    // Fetch videos for the menu
    axios.get(`${BASE_URL}/videos`)
      .then(response => {
        setUniqueVideoIDs(response.data);
      })
      .catch(error => {
        console.error('Error fetching videos: ', error);
      });
  }, []);

  function shuffleArray(array) {
    for (let i = array.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [array[i], array[j]] = [array[j], array[i]];
    }
    return array;
  }

  const handleCloseModal = () => {
    navigate('/');
  };

  return (
    <Router>
      <Routes>
        <Route path="/videos/:videoID" element={<Modal onClose={handleCloseModal} />} />
        <Route path="/" element={<App />} />
        <Route path="/video-grid" element={<VideoGrid scenes={scenes} />} />
      </Routes>
    </Router>
  );
}

export default AppWrapper;
